/// <summary>
/// The <c>ETGPurchRegisterReportDP</c> class is the report data provider class for Purchase register report
/// </summary>
[
    //SRSReportQueryAttribute(queryStr(ETGsalesRegisterReportQuery)),
    SRSReportParameterAttribute(classStr(Etg_RegisterSalesReportContract))
        ]
class Etg_RegisterSalesReportDP extends SrsReportDataProviderPreProcessTempDB
{

    Etg_RegisterSalesReportTemp     Etg_RegisterSalesReportTemp;
    Etg_RegisterSalesReportContract contract;
    FromDate                        fromDate;
    ToDate                          toDate;
    DimensionSetName                financialDimSet;
    NoYes                           isDetailReport;
    EcoResConfigurationFlag         viewConfigId;
    EcoResSizeFlag                  viewInventSizeId;
    EcoResColorFlag                 viewInventColorId;
    EcoResStyleFlag                 viewInventStyleId;
    InventSiteIdFlag                viewInventSiteId;
    InventLocationIdFlag            viewInventLocationId;
    WHSLicensePlateFlag             viewLicensePlate;
    InventLocationIdFlag            viewWMSLocationId;
    WHSInventStatusFlag             viewInventStatus;
    InventBatchIdFlag               viewInventBatchId;
    InventSerialIdFlag              viewInventSerialId;
    InventOwnerIdFlag               viewInventOwnerId;
    utcDateTime                     utcFromDate, utcToDate;
    PurchId                         currentPurchId;
    RefRecId                        currentPurchLine;
    salesTable                       salesTable;
    PurchTable                      purchTable;
    PurchLine                       purchLine;
    InventDim                       inventDim;
    salesLine                       salesLine;
    List                            custAccount = new List(Types::String);
    ETGBusinessSegment              etgBusinessSegment;
    ETGConnectionType               etgConnectionType;
    List       invoiceId = new List(Types::String);


}

Method.Source:
[SRSReportDataSetAttribute(tablestr(Etg_RegisterSalesReportTemp))]
public Etg_RegisterSalesReportTemp getEtg_RegisterSalesReportTemp()
{
    select Etg_RegisterSalesReportTemp;
    return Etg_RegisterSalesReportTemp;
}

/// <summary>
///    Parses the report parameters and fills the <c>ETGPurchRegisterReportTmp</c> and <c>ETGPurchRegisterReportTmp</c>
///    tables with data.
/// </summary>
public void initContract()
{
    contract                = this.parmDataContract() as Etg_RegisterSalesReportContract;
    fromDate                = contract.parmFromDate();
    toDate                  = contract.parmToDate();
    financialDimSet         = contract.parmFinancialDimSet();
    isDetailReport          = contract.parmIsDetailReport();
    viewConfigId            = contract.parmViewConfigId();
    viewInventSizeId        = contract.parmViewInventSizeId();
    viewInventColorId       = contract.parmViewInventColorId();
    viewInventStyleId       = contract.parmViewInventStyleId();
    viewInventSiteId        = contract.parmViewInventSiteId();
    viewInventLocationId    = contract.parmViewInventLocationId();
    viewLicensePlate        = contract.parmViewLicensePlateId();
    viewWMSLocationId       = contract.parmViewWMSLocationId();
    viewInventStatus        = contract.parmViewInventStatus();
    viewInventBatchId       = contract.parmViewInventBatchId();
    viewInventSerialId      = contract.parmViewInventSerialId();
    viewInventOwnerId       = contract.parmViewInventOwnerId_RU();
    etgBusinessSegment      = contract.parmBusinessSegment();
    etgConnectionType       = contract.parmConnectionType();
    custAccount             = contract.parmCustAccount();
    invoiceId               = contract.parmInvoiceId();
}

/// <summary>
///    inserting data useing parm query
/// </summary>
public void insertData()
{
    QueryRun                            queryRun;
    VendTrans                           vendTrans;
    AgreementHeader                     agreementHeader;
    AgreementLine                       agreementLine;
    SalesAgreementHeader                salesAgreementHeader;
    ETG_SalesTableTrade                 ETG_SalesTableTrade;
    CustPackingSlipJour                 custPackingSlipJour;
    CustPackingSlipTrans                custPackingSlipTrans;
    CustInvoiceJour                     custInvoiceJour;
    CustInvoiceTrans                    custInvoiceTrans;
    ETG_OrderType                       orderType;
    // Query                           query = this.parmQuery();
    InventTrans                         inventTrans;
    ETG_SALESAGREEMENTHEADER            ETG_SALESAGREEMENTHEADER;
    ETG_AgreementType                   AgreementType;
    DimensionAttributeValueSetStorage   dimStorage;
    InventTransOrigin                   InventTransOrigin  ;
    QueryBuildDataSource                qbds, queryBuildDataSourceCustInvoiceJour, queryBuildDataSourceCustInvoiceTrans;
    QueryBuildRange                     queryBuildRange, qbr;
    ListEnumerator                      listEnumerator;
    Query                               query;
    TaxTrans                            taxTrans;
    CompanyInfo                         companyInfo;
    InventTable                         inventTable;
    CustGroup                           custGroup;
    ETG_BillOfLading                        eTG_BillOfLading, billOfLading;
    Ledger ledgerOrg;
    ExchangeRateCurrencyPair exchangeRateCurrencyPair;
    ExchRate exchRate, exchValueCount;
    CurrencyCode           reportingCurrency = 'USD';
    RecId                  ledgerRecId;
    CurrencyExchangeHelper exchangeHelper;
    AmountMST              convertedAmount;
    real                   effectiveRate;


    utcFromDate = DateTimeUtil::newDateTime(fromDate, 0);
    utcToDate   = DateTimeUtil::newDateTime(toDate, 86400);
    //query.dataSourceTable(tablenum(CustInvoiceJour)).addRange(fieldnum(CustInvoiceJour, InvoiceDate)).value(queryRange(FromDate,ToDate));
    //query.dataSourceTable(tablenum(CustInvoiceJour)).addRange(fieldnum(CustInvoiceJour, SalesType)).value(any2Str(SalesType::Sales));

    // queryRun = new QueryRun(query);
    // while (queryRun.next())
    query = new Query();

    queryBuildDataSourceCustInvoiceJour           = query.addDataSource(tableNum(CustInvoiceJour));
    queryBuildDataSourceCustInvoiceTrans          = queryBuildDataSourceCustInvoiceJour.addDataSource(tableNum(CustInvoiceTrans));
    queryBuildDataSourceCustInvoiceTrans.joinMode(JoinMode::InnerJoin);
    queryBuildDataSourceCustInvoiceTrans.relations(true);
    queryBuildDataSourceCustInvoiceTrans.addLink(fieldNum(CustInvoiceJour, SalesId), fieldNum(CustInvoiceTrans, SalesId));
    queryBuildDataSourceCustInvoiceTrans.addLink(fieldNum(CustInvoiceJour, InvoiceId), fieldNum(CustInvoiceTrans, InvoiceId));
    queryBuildDataSourceCustInvoiceTrans.addLink(fieldNum(CustInvoiceJour, InvoiceDate), fieldNum(CustInvoiceTrans, InvoiceDate));

    query.dataSourceTable(tableNum(CustInvoiceJour)).addRange(fieldNum(CustInvoiceJour, InvoiceDate)).value(queryRange(fromDate, toDate));
    query.dataSourceTable(tablenum(CustInvoiceJour)).addRange(fieldnum(CustInvoiceJour, SalesType)).value(any2Str(SalesType::Sales));
    queryBuildDataSourceCustInvoiceJour.addSortField(fieldNum(CustInvoiceJour, InvoiceId),SortOrder::Ascending);

    if(custAccount != null)
    {
        listEnumerator = custAccount.getEnumerator();
        while(listEnumerator.moveNext())
        {
            queryBuildDataSourceCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, InvoiceAccount)).value(listEnumerator.current());
        }
    }

    if(invoiceId != null)
    {
        listEnumerator = invoiceId.getEnumerator();
        while(listEnumerator.moveNext())
        {
            queryBuildDataSourceCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, InvoiceId)).value(listEnumerator.current());
        }
    }

    if(etgBusinessSegment)
    {
        queryBuildRange = queryBuildDataSourceCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, ETGBusinessSegment));
        queryBuildRange.value(queryValue(etgBusinessSegment));
    }
    if(etgConnectionType)
    {
        queryBuildRange = queryBuildDataSourceCustInvoiceTrans.addRange(fieldNum(CustInvoiceTrans, ETGConnectionType));
        queryBuildRange.value(queryValue(etgConnectionType));
    }

    queryRun = new QueryRun(query);

    while(queryRun.next())


    /*while select CustInvoiceJour where CustInvoiceJour.InvoiceDate >= fromDate
                                   &&  CustInvoiceJour.InvoiceDate <= todate
                                   &&  CustInvoiceJour.SalesType == salestype::Sales
        if(CustInvoiceJour)*/
    {
        custInvoiceJour         = queryRun.get(tableNum(CustInvoiceJour));
        custInvoiceTrans        = queryRun.get(tableNum(CustInvoiceTrans));


        Etg_RegisterSalesReportTemp.clear();

        Etg_RegisterSalesReportTemp.InvoiceNumber      = CustInvoiceJour.InvoiceId;
        Etg_RegisterSalesReportTemp.TransDate          = DateTimeUtil::date(CustInvoiceJour.InvoiceDate);
        // Etg_RegisterSalesReportTemp.Quantity           = CustInvoiceJour.Qty;
        Etg_RegisterSalesReportTemp.Quantity           = custInvoiceTrans.Qty;


        select sum(SourceRegulateAmountCur) from taxTrans
            where taxTrans.SourceRecId == custInvoiceTrans.RecId;

        if(taxTrans)
        {
            Etg_RegisterSalesReportTemp.TaxAmount          = -taxTrans.SourceRegulateAmountCur;
        }
        Etg_RegisterSalesReportTemp.Amount = CustInvoiceJour.InvoiceAmount;
        Etg_RegisterSalesReportTemp.InvoiceAmountExcludeTax  = CustInvoiceJour.InvoiceAmountMST;

        Etg_RegisterSalesReportTemp.AmountInTransactionCurrency = custInvoiceTrans.LineAmount;           // + Etg_RegisterSalesReportTemp.TaxAmount;
        Etg_RegisterSalesReportTemp.AmountInAccountingCurrency  = custInvoiceTrans.LineAmountMST;         //+ Etg_RegisterSalesReportTemp.TaxAmount;




        // --- Reporting currency conversion logic ---
        if (custInvoiceTrans.CurrencyCode == reportingCurrency)
        {
            // No conversion needed
            Etg_RegisterSalesReportTemp.ExchangeRate              = 1.0;
            Etg_RegisterSalesReportTemp.AmountInReportingCurrency = custInvoiceTrans.LineAmount;
        }
        else
        {
            ledgerRecId = Ledger::primaryLedger(
                CompanyInfo::findDataArea(custInvoiceTrans.dataAreaId).RecId);


            exchangeHelper = CurrencyExchangeHelper::newExchangeDate(
    ledgerRecId,
    CustInvoiceJour::findRecId(custInvoiceTrans.ParentRecId).InvoiceDate
);

            convertedAmount = exchangeHelper.calculateCurrencyToCurrency(
    custInvoiceTrans.CurrencyCode,   // from (transaction currency)
    reportingCurrency,                // to   (USD)
    custInvoiceTrans.LineAmount,
    true                              // round
);

            // Derive effective exchange rate for display
            effectiveRate = (custInvoiceTrans.LineAmount != 0)
    ? convertedAmount / custInvoiceTrans.LineAmount
    : 0;

            Etg_RegisterSalesReportTemp.ExchangeRate              = effectiveRate;
            Etg_RegisterSalesReportTemp.AmountInReportingCurrency = convertedAmount;
        }



        Etg_RegisterSalesReportTemp.VendorCode         = CustInvoiceJour.InvoiceAccount;
        Etg_RegisterSalesReportTemp.VendorName         = custTable::find(CustInvoiceJour.InvoiceAccount).name();



        //Etg_RegisterSalesReportTemp.TaxAmount          = CustInvoiceJour.SumTax;
        Etg_RegisterSalesReportTemp.TaxGroup           = CustInvoiceJour.TaxGroup;
        Etg_RegisterSalesReportTemp.PONumber           = CustInvoiceJour.SalesId;
        Etg_RegisterSalesReportTemp.Currency           = CustInvoiceJour.CurrencyCode;
        Etg_RegisterSalesReportTemp.IncoTerms          = CustInvoiceJour.DlvTerm;
        Etg_RegisterSalesReportTemp.ETGVoucher         = CustInvoiceJour.LedgerVoucher;


        select firstonly salesTable
            where salesTable.SalesId ==  CustInvoiceJour.SalesId;

        Etg_RegisterSalesReportTemp.CustomerGroupName  = custGroup::find(salesTable.CustGroup).Name;

        select firstonly ETG_SalesTableTrade
            where ETG_SalesTableTrade.SalesId ==  salesTable.SalesId;


        Etg_RegisterSalesReportTemp.Remarks           = ETG_SalesTableTrade.Remarks;
        Etg_RegisterSalesReportTemp.PortofLoading     = ETG_SalesTableTrade.PortOfLoadingDesc;
        Etg_RegisterSalesReportTemp.PortOfDischarge   = ETG_SalesTableTrade.PortOfDischargeDesc;
        Etg_RegisterSalesReportTemp.Country           = ETG_SalesTableTrade.CountryOfOriginOfGoods;
        // Code Added by siva for the ACF requirement - Start - 18/08/2025
        if(curext() == "O001")
        {
            ETG_PlaceOfDischarge    ETG_PlaceOfDischarge;

            select * from ETG_PlaceOfDischarge where ETG_PlaceOfDischarge.Description == Etg_RegisterSalesReportTemp.PortOfDischarge;

            Etg_RegisterSalesReportTemp.SalesDestination  = ETG_PlaceOfDischarge.Country;
        }
        else
        {
            Etg_RegisterSalesReportTemp.SalesDestination  = ETG_SalesTableTrade.CountryOfFinalDestination;
        }
        // Code Added by siva for the ACF requirement - End - 18/08/2025
        //Etg_RegisterSalesReportTemp.SalesDestination  = ETG_SalesTableTrade.CountryOfFinalDestination;
        Etg_RegisterSalesReportTemp.BillOfLadingNumber     = CustInvoiceJour.ETG_BLnumber;

        select firstonly ETG_SALESAGREEMENTHEADER
           where ETG_SALESAGREEMENTHEADER.RecId ==  salesTable.MatchingAgreement;
        Etg_RegisterSalesReportTemp.PurchaseContractNumber   = salesAgreementHeader::find(salesTable.MatchingAgreement).SalesNumberSequence;
        Etg_RegisterSalesReportTemp.ContractOrderType   = ETG_SALESAGREEMENTHEADER.AgreementType;

        /* select firstonly inventTrans
            where inventTrans.InvoiceId ==   CustInvoiceJour.InvoiceId; */
        select firstonly inventTrans
            where inventTrans.InvoiceId ==   custInvoiceTrans.InvoiceId;
        /* select firstonly custInvoiceTrans
            where custInvoiceTrans.InvoiceId == CustInvoiceJour.InvoiceId ;
       */

        //  Etg_RegisterSalesReportTemp.Commodity          = inventTrans.ItemId;
        Etg_RegisterSalesReportTemp.Commodity          = custInvoiceTrans.ItemId;
        Etg_RegisterSalesReportTemp.UOM                = custInvoiceTrans.SalesUnit;
        Etg_RegisterSalesReportTemp.UnitPrice          = custInvoiceTrans.SalesPrice;

        select firstonly inventdim
            where inventdim.inventDimId ==   custInvoiceTrans.InventDimId;


        Etg_RegisterSalesReportTemp.Brand       = inventDim.InventStyleId;
        Etg_RegisterSalesReportTemp.Grade       = inventDim.configId;
        // Etg_RegisterSalesReportTemp.Size        = inventDim.InventSizeId;
        Etg_RegisterSalesReportTemp.Site        = inventDim.InventSiteId;
        Etg_RegisterSalesReportTemp.Origin      = inventDim.InventColorId;
        Etg_RegisterSalesReportTemp.BatchNumber = inventDim.inventBatchId;
        Etg_RegisterSalesReportTemp.Location    = inventDim.wMSLocationId;
        Etg_RegisterSalesReportTemp.WareHouse   = inventDim.InventLocationId;
        Etg_RegisterSalesReportTemp.SerialNumber   = inventDim.inventSerialId;

        // Etg_registerPurchTemp.InventLocationName   = InventLocation::find(inventDim.InventLocationId).Name;

        dimStorage = DimensionAttributeValueSetStorage::find(CustInvoiceJour.DefaultDimension);
        Etg_RegisterSalesReportTemp.Vertical    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('Vertical').RecId);
        Etg_RegisterSalesReportTemp.SubVertical    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('SubVertical').RecId);
        Etg_RegisterSalesReportTemp.ProfitCenter    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('ProfitCenter').RecId);
        Etg_RegisterSalesReportTemp.BusinessUnit    =  dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName('BusinessUnit').RecId);


        Etg_RegisterSalesReportTemp.ETGBusinessSegment  = custInvoiceJour.ETGBusinessSegment;
        Etg_RegisterSalesReportTemp.ETGConnectionType   = custInvoiceTrans.ETGConnectionType;
        Etg_RegisterSalesReportTemp.ETGDepositAmount    = custInvoiceTrans.ETGDepositAmount;
        Etg_RegisterSalesReportTemp.ETGDepositRate      = custInvoiceTrans.ETGDepositRate;

        InventTableModule inventTableModule = InventTableModule::find(custInvoiceTrans.ItemId, ModuleInventPurchSales::Sales);
        Etg_RegisterSalesReportTemp.ETGPackSize = inventTableModule.ETGPackSize;


        UnitOfMeasureConversion  unitOfMeasureConversion;
        InventTable inventTableLoc = InventTable::find(custInvoiceTrans.ItemId);
        UnitOfMeasureRecId       fromUnitId     = UnitOfMeasure::unitOfMeasureIdBySymbol(inventTableLoc.inventUnitId());
        select firstonly  unitOfMeasureConversion
               where      unitOfMeasureConversion.Product           == inventTableLoc.Product
               &&         unitOfMeasureConversion.FromUnitOfMeasure == fromUnitId;

        Etg_RegisterSalesReportTemp.ETGAlternateUOM         = UnitOfMeasure::find(unitOfMeasureConversion.ToUnitOfMeasure).Symbol;
        Etg_RegisterSalesReportTemp.ETGQtywithalternateUOM  = custInvoiceTrans.Qty * unitOfMeasureConversion.Factor;

        select * from companyInfo where companyInfo.DataArea == curExt();

        Etg_RegisterSalesReportTemp.ETGCompanyName = companyInfo.name();
        Etg_RegisterSalesReportTemp.ETGCompanyLogo = FormLetter::companyLogo();
        Etg_RegisterSalesReportTemp.ETGMainCommodity = inventTableLoc.ETGCommodity;
        Etg_RegisterSalesReportTemp.ETGSubCommodity  = inventTableLoc.ETGSubCommodity;
        Etg_RegisterSalesReportTemp.ETGVesselName    = ETG_SalesTableTrade.VesselName;
        int num = mthOfYr(Etg_RegisterSalesReportTemp.TransDate);
        Etg_RegisterSalesReportTemp.ETGMonth = mthName(num);

        ItemId itemID = "";
        itemID = custInvoiceTrans.ItemId;
        Etg_RegisterSalesReportTemp.ETGItemName      = EcoResProductTranslation::findByProductLanguage(InventTable::find(itemID).Product, SystemParameters::getSystemLanguageId()).Name;

        select * from ETG_BillOfLading where ETG_BillOfLading.SalesId==SalesTable.SalesId;

        Etg_RegisterSalesReportTemp.PickListNumber = ETG_BillOfLading.PickListNumber;

        select * from billOfLading where billOfLading.SalesId == SalesTable.SalesId;

        if(billOfLading.ETGDeliveryOrderNo != "")
        {
            Etg_RegisterSalesReportTemp.ETGDeliveryOrderNo = billOfLading.ETGDeliveryOrderNo;
        }
        else if(!Etg_RegisterSalesReportTemp.ETGDeliveryOrderNo)
        {
            while select billOfLading where billOfLading.SalesId == SalesTable.SalesId
            {
                //if(billOfLading.ETGDeliveryOrderNo != "")
                {
                    Etg_RegisterSalesReportTemp.ETGDeliveryOrderNo = billOfLading.ETGDeliveryOrderNo;
                }
            }
        }

        Etg_RegisterSalesReportTemp.insert();
    }

}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
{
    DimensionAttributeValueSetStorage   dimStorage;
    DimensionAttribute                  dimAttribute;
    DimensionValue                      displayValue = "";
    Description                         dimDescription = "";
    int                                 i;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
    for (i= 1 ; i<= dimStorage.elements() ; i++)
    {
        dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

        if(dimAttribute.Name == _dimensionName)
        {
            displayValue    = dimStorage.getDisplayValueByIndex(i);
            dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
            if (dimDescription == "")
            {
                dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
            }
        }
    }

    return  dimDescription;
}

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
{
    DimAttributeInventTable         inventTable;
    DimAttributeHcmWorker           worker;
    DimAttributeCustTable           custTable;
    DimAttributeVendTable           dimVendTable;
    DimAttributeAssetTable          assetTable;
    DimAttributeOMBusinessUnit      businessUnit;
    DimAttributeOMCostCenter        costCenter;
    DimAttributeOMDepartment        department;
    Description                     dimDescription = "";

    switch (_ViewName)
    {
        case  "DimAttributeInventTable":
                select Name from inventTable
                where inventTable.value == _displayValue;
            dimDescription = inventTable.Name;
            break;
        case  "DimAttributeHcmWorker":
                select Name from worker
                where worker.value == _displayValue;
            dimDescription = worker.Name;
            break;
        case  "DimAttributeCustTable":
                select Name from custTable
                where custTable.value == _displayValue;
            dimDescription = custTable.Name;
            break;
        case  "DimAttributeVendTable":
                select Name from dimVendTable
                where dimVendTable.value == _displayValue;
            dimDescription = dimVendTable.Name;
            break;
        case  "DimAttributeAssetTable":
                select Name from assetTable
                where assetTable.value == _displayValue;
            dimDescription = assetTable.Name;
            break;
        case  "DimAttributeOMBusinessUnit":
                select Name from businessUnit
                where businessUnit.value == _displayValue;
            dimDescription = businessUnit.Name;
            break;
        case  "DimAttributeOMCostCenter":
                select Name from costCenter
                where costCenter.value == _displayValue;
            dimDescription = costCenter.Name;
            break;
        case  "DimAttributeOMDepartment":
                select Name from department
                where department.value == _displayValue;
            dimDescription = department.Name;
            break;
    }

    return      dimDescription;
}

public boolean isDimensionIncludedInSet(Name        _setName, Name     _dimensionName)
{
    FinancialDimensionSetEntity     financialDimensionSetEntity;

    select firstonly financialDimensionSetEntity
        where financialDimensionSetEntity.Name == _setName
        && (financialDimensionSetEntity.SegmentName01 == _dimensionName ||
        financialDimensionSetEntity.SegmentName02 == _dimensionName ||
        financialDimensionSetEntity.SegmentName03 == _dimensionName ||
        financialDimensionSetEntity.SegmentName04 == _dimensionName ||
        financialDimensionSetEntity.SegmentName05 == _dimensionName ||
        financialDimensionSetEntity.SegmentName06 == _dimensionName ||
        financialDimensionSetEntity.SegmentName07 == _dimensionName ||
        financialDimensionSetEntity.SegmentName08 == _dimensionName ||
        financialDimensionSetEntity.SegmentName09 == _dimensionName ||
        financialDimensionSetEntity.SegmentName10 == _dimensionName ||
        financialDimensionSetEntity.SegmentName11 == _dimensionName
        );

    return financialDimensionSetEntity.RecId;
}
